import hashlib

def file_hash(filepath, algorithm='sha256', buffer_size=65536):
    """
    Generates a hash of a file for integrity checking.

    Args:
        filepath (str): The path to the file.
        algorithm (str): The hashing algorithm to use (e.g., 'md5', 'sha1', 'sha256', 'sha512').
                         Defaults to 'sha256'.
        buffer_size (int): The size of the buffer in bytes to read the file in chunks.
                           Defaults to 65536 (64 KB).

    Returns:
        str: The hexadecimal digest of the file's hash, or None if the file cannot be opened.
    """
    try:
        hasher = hashlib.new(algorithm)
    except ValueError:
        raise ValueError(f"Unsupported hashing algorithm: {algorithm}. "
                         f"Choose from {', '.join(hashlib.algorithms_available)}")

    try:
        with open(filepath, 'rb') as f:
            while True:
                data = f.read(buffer_size)
                if not data:
                    break
                hasher.update(data)
        return hasher.hexdigest()
    except IOError:
        return None